package value_test

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"testing"

	"k8s.io/apiserver/pkg/storage/value"
)

// simpleTransformer is a test Transformer that XORs each byte with a fixed key byte.
type simpleTransformer struct {
	key     byte
	fromErr error
	toErr   error
	stale   bool
}

func (s *simpleTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx value.Context) ([]byte, bool, error) {
	if s.fromErr != nil {
		return nil, false, s.fromErr
	}
	out := make([]byte, len(data))
	for i, b := range data {
		out[i] = b ^ s.key
	}
	return out, s.stale, nil
}

func (s *simpleTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx value.Context) ([]byte, error) {
	if s.toErr != nil {
		return nil, s.toErr
	}
	out := make([]byte, len(data))
	for i, b := range data {
		out[i] = b ^ s.key
	}
	return out, nil
}

// identityTransformer passes data through unchanged.
type identityTransformer struct{}

func (identityTransformer) TransformFromStorage(_ context.Context, data []byte, _ value.Context) ([]byte, bool, error) {
	return data, false, nil
}

func (identityTransformer) TransformToStorage(_ context.Context, data []byte, _ value.Context) ([]byte, error) {
	return data, nil
}

// TestDefaultContextAuthenticatedData verifies that DefaultContext returns its own bytes.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	input := []byte("some-key/namespace/resource")
	dc := value.DefaultContext(input)
	got := dc.AuthenticatedData()
	if !bytes.Equal(got, input) {
		t.Errorf("AuthenticatedData() = %q, want %q", got, input)
	}
}

// TestDefaultContextNil verifies that a nil DefaultContext returns nil.
func TestDefaultContextNil(t *testing.T) {
	var dc value.DefaultContext
	if got := dc.AuthenticatedData(); got != nil {
		t.Errorf("AuthenticatedData() on nil DefaultContext = %v, want nil", got)
	}
}

// TestTransformerRoundTrip verifies that TransformToStorage followed by TransformFromStorage
// recovers the original plaintext.
func TestTransformerRoundTrip(t *testing.T) {
	tests := []struct {
		name      string
		plaintext []byte
		key       byte
	}{
		{"simple ascii", []byte("hello world"), 0x42},
		{"empty input", []byte{}, 0x01},
		{"binary data", []byte{0x00, 0xFF, 0xAB, 0xCD}, 0x55},
		{"single byte", []byte{0x7F}, 0x7F},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			transformer := &simpleTransformer{key: tc.key}
			ctx := context.Background()
			dataCtx := value.DefaultContext([]byte("test-resource"))

			encrypted, err := transformer.TransformToStorage(ctx, tc.plaintext, dataCtx)
			if err != nil {
				t.Fatalf("TransformToStorage() error = %v", err)
			}

			recovered, stale, err := transformer.TransformFromStorage(ctx, encrypted, dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage() error = %v", err)
			}
			if stale {
				t.Errorf("TransformFromStorage() stale = true, want false")
			}
			if !bytes.Equal(recovered, tc.plaintext) {
				t.Errorf("round-trip mismatch: got %q, want %q", recovered, tc.plaintext)
			}
		})
	}
}

// TestPrefixTransformerToStorageAddsPrefix verifies that TransformToStorage prepends the prefix.
func TestPrefixTransformerToStorageAddsPrefix(t *testing.T) {
	prefix := []byte("k8s:enc:aescbc:v1:")
	inner := &simpleTransformer{key: 0x00} // identity when key=0
	pt := value.NewPrefixTransformers(nil, value.PrefixTransformer{
		Prefix:      prefix,
		Transformer: identityTransformer{},
	})

	ctx := context.Background()
	plaintext := []byte("secret-data")
	out, err := pt.TransformToStorage(ctx, plaintext, nil)
	if err != nil {
		t.Fatalf("TransformToStorage() error = %v", err)
	}
	if !bytes.HasPrefix(out, prefix) {
		t.Errorf("output %q does not start with prefix %q", out, prefix)
	}
	_ = inner
}

// TestPrefixTransformerFromStorageStripsPrefix verifies that TransformFromStorage removes the prefix
// before passing data to the inner transformer.
func TestPrefixTransformerFromStorageStripsPrefix(t *testing.T) {
	prefix := []byte("k8s:enc:aescbc:v1:")
	plaintext := []byte("my-secret")
	pt := value.NewPrefixTransformers(nil, value.PrefixTransformer{
		Prefix:      prefix,
		Transformer: identityTransformer{},
	})

	ctx := context.Background()
	// Manually construct prefixed data (as if written by TransformToStorage).
	prefixed := append(append([]byte{}, prefix...), plaintext...)
	out, stale, err := pt.TransformFromStorage(ctx, prefixed, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() error = %v", err)
	}
	if stale {
		t.Errorf("TransformFromStorage() stale = true for first transformer, want false")
	}
	if !bytes.Equal(out, plaintext) {
		t.Errorf("TransformFromStorage() = %q, want %q", out, plaintext)
	}
}

// TestPrefixTransformerMismatch verifies that when no prefix matches the data,
// TransformFromStorage returns the error passed to NewPrefixTransformers.
func TestPrefixTransformerMismatch(t *testing.T) {
	sentinel := errors.New("no matching transformer")
	pt := value.NewPrefixTransformers(sentinel, value.PrefixTransformer{
		Prefix:      []byte("k8s:enc:aescbc:v1:"),
		Transformer: identityTransformer{},
	})

	ctx := context.Background()
	_, _, err := pt.TransformFromStorage(ctx, []byte("unknown:data"), nil)
	if !errors.Is(err, sentinel) {
		t.Errorf("expected sentinel error %v, got %v", sentinel, err)
	}
}

// TestPrefixTransformerStaleOnNonFirstTransformer verifies that when a non-first transformer
// matches, the result is marked stale.
func TestPrefixTransformerStaleOnNonFirstTransformer(t *testing.T) {
	firstPrefix := []byte("new:")
	oldPrefix := []byte("old:")

	pt := value.NewPrefixTransformers(nil,
		value.PrefixTransformer{Prefix: firstPrefix, Transformer: identityTransformer{}},
		value.PrefixTransformer{Prefix: oldPrefix, Transformer: identityTransformer{}},
	)

	ctx := context.Background()
	// Data written with the old (second) prefix.
	data := append(append([]byte{}, oldPrefix...), []byte("payload")...)
	_, stale, err := pt.TransformFromStorage(ctx, data, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() error = %v", err)
	}
	if !stale {
		t.Error("TransformFromStorage() stale = false for non-first transformer match, want true")
	}
}

// TestPrefixTransformerErrorPropagation verifies that errors from the inner transformer
// are returned to the caller.
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	transformErr := fmt.Errorf("inner transform error")
	prefix := []byte("k8s:enc:")

	tests := []struct {
		name    string
		fromErr error
		toErr   error
	}{
		{"from-storage error", transformErr, nil},
		{"to-storage error", nil, transformErr},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			inner := &simpleTransformer{fromErr: tc.fromErr, toErr: tc.toErr}
			pt := value.NewPrefixTransformers(nil, value.PrefixTransformer{
				Prefix:      prefix,
				Transformer: inner,
			})
			ctx := context.Background()

			if tc.fromErr != nil {
				prefixed := append(append([]byte{}, prefix...), []byte("data")...)
				_, _, err := pt.TransformFromStorage(ctx, prefixed, nil)
				if err == nil {
					t.Error("TransformFromStorage() expected error, got nil")
				}
			}
			if tc.toErr != nil {
				_, err := pt.TransformToStorage(ctx, []byte("data"), nil)
				if err == nil {
					t.Error("TransformToStorage() expected error, got nil")
				}
			}
		})
	}
}

// TestPrefixTransformerMultipleTransformers is a table-driven test covering multiple
// prefix selection scenarios in TransformFromStorage.
func TestPrefixTransformerMultipleTransformers(t *testing.T) {
	errNoMatch := errors.New("no match")
	errInner := errors.New("inner error")

	tests := []struct {
		name        string
		input       []byte
		wantOutput  []byte
		wantStale   bool
		wantErr     error
	}{
		{
			name:       "first prefix matches",
			input:      []byte("alpha:payload"),
			wantOutput: []byte("payload"),
			wantStale:  false,
			wantErr:    nil,
		},
		{
			name:       "second prefix matches (stale)",
			input:      []byte("beta:payload"),
			wantOutput: []byte("payload"),
			wantStale:  true,
			wantErr:    nil,
		},
		{
			name:      "no prefix matches",
			input:     []byte("gamma:payload"),
			wantStale: false,
			wantErr:   errNoMatch,
		},
		{
			name:      "matching prefix but inner error",
			input:     []byte("fails:payload"),
			wantStale: false,
			wantErr:   errInner,
		},
	}

	pt := value.NewPrefixTransformers(errNoMatch,
		value.PrefixTransformer{Prefix: []byte("alpha:"), Transformer: identityTransformer{}},
		value.PrefixTransformer{Prefix: []byte("beta:"), Transformer: identityTransformer{}},
		value.PrefixTransformer{Prefix: []byte("fails:"), Transformer: &simpleTransformer{fromErr: errInner}},
	)

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			out, stale, err := pt.TransformFromStorage(ctx, tc.input, nil)

			if tc.wantErr != nil {
				if err == nil {
					t.Fatalf("expected error %v, got nil", tc.wantErr)
				}
				// Don't check exact error equality — aggregate errors wrap originals.
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if stale != tc.wantStale {
				t.Errorf("stale = %v, want %v", stale, tc.wantStale)
			}
			if !bytes.Equal(out, tc.wantOutput) {
				t.Errorf("output = %q, want %q", out, tc.wantOutput)
			}
		})
	}
}

// TestPrefixTransformerRoundTrip verifies the full write/read cycle through NewPrefixTransformers.
func TestPrefixTransformerRoundTrip(t *testing.T) {
	prefix := []byte("k8s:enc:v1:")
	pt := value.NewPrefixTransformers(nil, value.PrefixTransformer{
		Prefix:      prefix,
		Transformer: &simpleTransformer{key: 0xAB},
	})

	ctx := context.Background()
	dataCtx := value.DefaultContext([]byte("/registry/secrets/default/mysecret"))
	plaintext := []byte("very-secret-value")

	encrypted, err := pt.TransformToStorage(ctx, plaintext, dataCtx)
	if err != nil {
		t.Fatalf("TransformToStorage() error = %v", err)
	}
	if !bytes.HasPrefix(encrypted, prefix) {
		t.Errorf("encrypted output %q does not start with prefix %q", encrypted, prefix)
	}

	recovered, stale, err := pt.TransformFromStorage(ctx, encrypted, dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage() error = %v", err)
	}
	if stale {
		t.Error("TransformFromStorage() stale = true for first transformer, want false")
	}
	if !bytes.Equal(recovered, plaintext) {
		t.Errorf("recovered %q, want %q", recovered, plaintext)
	}
}

// TestNewPrefixTransformersDefaultError verifies that NewPrefixTransformers uses a sensible
// default error when nil is passed, and that it is non-nil.
func TestNewPrefixTransformersDefaultError(t *testing.T) {
	// Pass nil as the error — the implementation should substitute a default.
	pt := value.NewPrefixTransformers(nil, value.PrefixTransformer{
		Prefix:      []byte("known:"),
		Transformer: identityTransformer{},
	})
	ctx := context.Background()

	// Data with an unknown prefix should produce a non-nil error.
	_, _, err := pt.TransformFromStorage(ctx, []byte("unknown:data"), nil)
	if err == nil {
		t.Error("expected non-nil error for unrecognised prefix, got nil")
	}
}

