// TestPrefixTransformerStaleOnNonFirstTransformer verifies that when a non-first transformer
// matches, the result is marked stale (requiring re-encryption with the preferred transformer).
func TestPrefixTransformerStaleOnNonFirstTransformer(t *testing.T) {
	firstPrefix := []byte("new:")
	oldPrefix := []byte("old:")

	pt := value.NewPrefixTransformers(nil,
		value.PrefixTransformer{Prefix: firstPrefix, Transformer: identityTransformer{}},
		value.PrefixTransformer{Prefix: oldPrefix, Transformer: identityTransformer{}},
	)

	ctx := context.Background()
	data := append(append([]byte{}, oldPrefix...), []byte("payload")...)
	_, stale, err := pt.TransformFromStorage(ctx, data, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage() error = %v", err)
	}
	if !stale {
		t.Error("TransformFromStorage() stale = false for non-first transformer match, want true")
	}
}

// TestPrefixTransformerErrorPropagation verifies that errors from the inner transformer
// are returned to the caller.
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	transformErr := fmt.Errorf("inner transform error")
	prefix := []byte("k8s:enc:")

	tests := []struct {
		name    string
		fromErr error
		toErr   error
	}{
		{"from-storage error", transformErr, nil},
		{"to-storage error", nil, transformErr},
	}

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			inner := &simpleTransformer{fromErr: tc.fromErr, toErr: tc.toErr}
			pt := value.NewPrefixTransformers(nil, value.PrefixTransformer{
				Prefix:      prefix,
				Transformer: inner,
			})
			ctx := context.Background()

			if tc.fromErr != nil {
				prefixed := append(append([]byte{}, prefix...), []byte("data")...)
				_, _, err := pt.TransformFromStorage(ctx, prefixed, nil)
				if err == nil {
					t.Error("TransformFromStorage() expected error, got nil")
				}
			}
			if tc.toErr != nil {
				_, err := pt.TransformToStorage(ctx, []byte("data"), nil)
				if err == nil {
					t.Error("TransformToStorage() expected error, got nil")
				}
			}
		})
	}
}

// TestPrefixTransformerMultipleTransformers is a table-driven test covering multiple
// prefix selection scenarios in TransformFromStorage.
func TestPrefixTransformerMultipleTransformers(t *testing.T) {
	errNoMatch := errors.New("no match")
	errInner := errors.New("inner error")

	tests := []struct {
		name       string
		input      []byte
		wantOutput []byte
		wantStale  bool
		wantErr    bool
	}{
		{
			name:       "first prefix matches",
			input:      []byte("alpha:payload"),
			wantOutput: []byte("payload"),
			wantStale:  false,
			wantErr:    false,
		},
		{
			name:       "second prefix matches (stale)",
			input:      []byte("beta:payload"),
			wantOutput: []byte("payload"),
			wantStale:  true,
			wantErr:    false,
		},
		{
			name:      "no prefix matches",
			input:     []byte("gamma:payload"),
			wantStale: false,
			wantErr:   true,
		},
		{
			name:    "matching prefix but inner error",
			input:   []byte("fails:payload"),
			wantErr: true,
		},
	}

	pt := value.NewPrefixTransformers(errNoMatch,
		value.PrefixTransformer{Prefix: []byte("alpha:"), Transformer: identityTransformer{}},
		value.PrefixTransformer{Prefix: []byte("beta:"), Transformer: identityTransformer{}},
		value.PrefixTransformer{Prefix: []byte("fails:"), Transformer: &simpleTransformer{fromErr: errInner}},
	)

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			out, stale, err := pt.TransformFromStorage(ctx, tc.input, nil)

			if tc.wantErr {
				if err == nil {
					t.Fatalf("expected error, got nil (output=%q)", out)
				}
				return
			}
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}
			if stale != tc.wantStale {
				t.Errorf("stale = %v, want %v", stale, tc.wantStale)
			}
			if !bytes.Equal(out, tc.wantOutput) {
				t.Errorf("output = %q, want %q", out, tc.wantOutput)
			}
		})
	}
}

